  let bestNs = events[0].epochNanoseconds;
  for (let i = 1; i < events.length; i++) {
    const ns = events[i].epochNanoseconds;
    if (ns > bestNs) {
      bestNs = ns;
      bestIndex = i;
    }
  }
  return BigInt(bestIndex);
}
